query Community($skip: Int, $orderBy: OrderByInput, $where: CommunityWhereInput, $limit: Int) {
  community(skip: $skip, orderBy: $orderBy, where: $where, limit: $limit) {
    total
    data {
      id
      isRead
      catalog {
        id
        title
      }
      title
      subImages
      description
      files
      videos
      isPublic
      createdAt
      updatedAt
      image
    }
  }
}

query NotiFications($limit: Int, $skip: Int, $orderBy: OrderByInput, $where: NotiFicationWhereInput) {
  notiFications(limit: $limit, skip: $skip, orderBy: $orderBy, where: $where) {
    data {
      description
      id_notification
      isRead
      notiDate
      readDate
      title
      type
      id_profile {
        BANK_NAME
        BANK_THB
        BANK_USD
        Bank_KIP
        id_list
        full_name
      }
      createdAt
    }
  }
}

